mapper.select:
		SELECT usvc_outb_id, evt_svc_nm, evt_typ, evt_typ_cd, msg_typ_cd, evt_nm,
				evt_cntn, outb_pos_nm, outb_posx, outb_posy, evt_outb_dtm, evt_clr_dtm,
				evt_proc_cd, evt_actn_dtm, evt_actn_usrid, evt_actn_cntn, test_yn, evt_json,

				emd.emd_kor_nm

		FROM xeus.v_mon_evet_list hist
		LEFT JOIN xeus.kais_emd_as AS emd ON st_intersects ( emd._geometry, hist._geometry )


		test_yn = 'N'
		AND hist.evt_typ_cd IS NOT NULL

				AND hist.evt_outb_dtm LIKE #{year}||'%'


				AND hist.evt_outb_dtm LIKE '____'||#{month}||'%'


           		AND emd.emd_cd = #{emdCd}




				AND usvc_outb_id = #{usvcOutbId}


				AND usvc_outb_id = #{uSvcOutbId}




				AND evt_svc_nm = #{evtSvcNm}


				AND evt_svc_nm = #{statEvetNm}




				AND evt_typ = #{evtTyp}


				AND evt_typ = #{statEvetType}




				AND evt_typ_cd = #{evtTypCd}


				AND evt_typ_cd = #{statEvetTypCd}




				AND evt_typ_cd in

					#{item}





				AND msg_typ_cd = #{msgTypCd}


				AND msg_typ_cd = #{statMsgTypCd}




				AND evt_nm = #{evtNm}


				AND evt_nm = #{statEvetNm}




				AND evt_cntn = #{evtCntn}


				AND evt_cntn = #{statEvetCntn}




				AND outb_pos_nm = #{outbPosNm}




				AND outb_posx = #{outbPosx}::numeric




				AND outb_posy = #{outbPosy}::numeric




				AND evt_outb_dtm like '%'||#{evtOutbDtm}||'%'



				AND evt_outb_dtm  >=  #{startDat}



				AND evt_outb_dtm  <=  #{endDat}



				AND evt_outb_dtm like '%'||#{statEvetOutbDtm}||'%'




				AND evt_clr_dtm = #{evtClrDtm}


				AND evt_clr_dtm = #{statEvetClrDtm}




				AND evt_proc_cd = #{evtProcCd}


				AND evt_proc_cd = #{procSt}




				AND evt_actn_dtm = #{evtActnDtm}


				AND evt_actn_dtm = #{statEvetActnDtm}




				AND evt_actn_usrid = #{evtActnUsrid}


				AND evt_actn_usrid = #{statEvetActnMn}




				AND evt_actn_cntn = #{evtActnCntn}


				AND evt_actn_cntn = #{statEvetActnCntn}




				AND test_yn = #{testYn}


				AND test_yn = #{isTest}




				AND evt_json = #{evtJson}


				AND evt_json = #{etcCntn}




				AND _gid = #{gid}::numeric






				${sortCol} ${sortTyp}


				evt_outb_dtm desc




			LIMIT ${limit} OFFSET ${offset}

SELECT usvc_outb_id, evt_svc_nm, evt_typ, evt_typ_cd, msg_typ_cd, evt_nm, evt_cntn, outb_pos_nm, outb_posx, outb_posy, evt_outb_dtm, evt_clr_dtm, evt_proc_cd, evt_actn_dtm, evt_actn_usrid, evt_actn_cntn, test_yn, evt_json


FROM xeus.mon_evet_hist


test_yn = 'N'


		AND usvc_outb_id = #{usvcOutbId}


		AND usvc_outb_id = #{uSvcOutbId}




		AND evt_svc_nm = #{evtSvcNm}


		AND evt_svc_nm = #{statEvetNm}




		AND evt_typ = #{evtTyp}


		AND evt_typ = #{statEvetType}




		AND evt_typ_cd = #{evtTypCd}


		AND evt_typ_cd = #{statEvetTypCd}




		AND msg_typ_cd = #{msgTypCd}


		AND msg_typ_cd = #{statMsgTypCd}




		AND evt_nm = #{evtNm}


		AND evt_nm = #{statEvetNm}




		AND evt_cntn = #{evtCntn}


		AND evt_cntn = #{statEvetCntn}




		AND outb_pos_nm = #{outbPosNm}




		AND outb_posx = #{outbPosx}::numeric




		AND outb_posy = #{outbPosy}::numeric




		AND evt_outb_dtm like '%'||#{evtOutbDtm}||'%'



		AND evt_outb_dtm  >=  #{startDat}



		AND evt_outb_dtm  <=  #{endDat}



		AND evt_outb_dtm like '%'||#{statEvetOutbDtm}||'%'




		AND evt_clr_dtm = #{evtClrDtm}


		AND evt_clr_dtm = #{statEvetClrDtm}




		AND evt_proc_cd = #{evtProcCd}


		AND evt_proc_cd = #{procSt}




		AND evt_actn_dtm = #{evtActnDtm}


		AND evt_actn_dtm = #{statEvetActnDtm}




		AND evt_actn_usrid = #{evtActnUsrid}


		AND evt_actn_usrid = #{statEvetActnMn}




		AND evt_actn_cntn = #{evtActnCntn}


		AND evt_actn_cntn = #{statEvetActnCntn}




		AND test_yn = #{testYn}


		AND test_yn = #{isTest}




		AND evt_json = #{evtJson}


		AND evt_json = #{etcCntn}

		SELECT count(*)

		FROM xeus.mon_evet_hist hist
		LEFT JOIN xeus.kais_emd_as AS emd ON st_intersects ( emd._geometry, hist._geometry )


		test_yn = 'N' AND evt_nm is not null and evt_nm != 'null'


				AND hist.evt_outb_dtm LIKE #{year}||'%'


				AND hist.evt_outb_dtm LIKE '____'||#{month}||'%'


           		AND emd.emd_cd = #{emdCd}



				AND usvc_outb_id = #{usvcOutbId}


				AND usvc_outb_id = #{uSvcOutbId}




				AND evt_svc_nm = #{evtSvcNm}


				AND evt_svc_nm = #{statEvetNm}




				AND evt_typ = #{evtTyp}


				AND evt_typ = #{statEvetType}




				AND evt_typ_cd = #{evtTypCd}


				AND evt_typ_cd = #{statEvetTypCd}




				AND evt_typ_cd in

					#{item}





				AND msg_typ_cd = #{msgTypCd}


				AND msg_typ_cd = #{statMsgTypCd}




				AND evt_nm = #{evtNm}


				AND evt_nm = #{statEvetNm}




				AND evt_cntn = #{evtCntn}


				AND evt_cntn = #{statEvetCntn}




				AND outb_pos_nm = #{outbPosNm}




				AND outb_posx = #{outbPosx}::numeric




				AND outb_posy = #{outbPosy}::numeric




				AND evt_outb_dtm like '%'||#{evtOutbDtm}||'%'


				AND evt_outb_dtm like '%'||#{statEvetOutbDtm}||'%'




				AND evt_clr_dtm = #{evtClrDtm}


				AND evt_clr_dtm = #{statEvetClrDtm}




				AND evt_proc_cd = #{evtProcCd}


				AND evt_proc_cd = #{procSt}




				AND evt_actn_dtm = #{evtActnDtm}


				AND evt_actn_dtm = #{statEvetActnDtm}




				AND evt_actn_usrid = #{evtActnUsrid}


				AND evt_actn_usrid = #{statEvetActnMn}




				AND evt_actn_cntn = #{evtActnCntn}


				AND evt_actn_cntn = #{statEvetActnCntn}




				AND test_yn = #{testYn}


				AND test_yn = #{isTest}




				AND evt_json = #{evtJson}


				AND evt_json = #{etcCntn}




				AND _gid = #{gid}::numeric




				AND evt_outb_dtm  >=  #{startDat}



				AND evt_outb_dtm  <=  #{endDat}

SELECT log.month AS month, count(log.month) AS count FROM ( SELECT substring(log.evt_outb_dtm, 5, 2) AS month FROM xeus.v_mon_evet_list log LEFT JOIN xeus.kais_emd_as AS emd ON st_intersects(emd._geometry, log._geometry)
log.evt_typ_cd IS NOT NULL AND test_yn = 'N'
AND log.evt_outb_dtm LIKE #{year}||'%'
AND log.evt_typ_cd = #{evtTypCd}
AND emd.emd_cd = #{emdCd}
) log GROUP BY log.month ORDER BY log.month

SELECT log.day AS day, count(log.day) AS count FROM ( SELECT substring(log.evt_outb_dtm, 7, 2) AS day FROM xeus.v_mon_evet_list log LEFT JOIN xeus.kais_emd_as AS emd ON st_intersects(emd._geometry, log._geometry)
log.evt_typ_cd IS NOT NULL AND test_yn = 'N'
AND log.evt_outb_dtm LIKE #{year}||'%'
AND log.evt_outb_dtm LIKE '____'||#{month}||'%'
AND log.evt_typ_cd = #{evtTypCd}
AND emd.emd_cd = #{emdCd}
) log GROUP BY log.day ORDER BY log.day

		SELECT
			COUNT(hist.evt_nm) AS count, hist.evt_typ_cd, hist.evt_nm
		FROM
			xeus.v_mon_evet_list hist
			LEFT JOIN xeus.kais_emd_as AS emd ON st_intersects ( emd._geometry, hist._geometry )


				hist.evt_typ_cd IS NOT NULL AND test_yn = 'N'

					AND hist.evt_outb_dtm LIKE #{year}||'%'


					AND hist.evt_outb_dtm LIKE '____'||#{month}||'%'


					AND hist.evt_typ_cd = #{evtTypCd}


               		AND emd.emd_cd = #{emdCd}


					AND evt_outb_dtm  >=  #{startDat}



					AND evt_outb_dtm  <=  #{endDat}




			GROUP BY evt_typ_cd,evt_nm

		SELECT
			COUNT(hist.evt_typ_cd) AS count, hist.evt_typ_cd
		FROM
			xeus.v_mon_evet_list hist
			LEFT JOIN xeus.kais_emd_as AS emd ON st_intersects ( emd._geometry, hist._geometry )


				hist.evt_typ_cd IS NOT NULL AND test_yn = 'N'

					AND hist.evt_outb_dtm LIKE #{year}||'%'


					AND hist.evt_outb_dtm LIKE '____'||#{month}||'%'


					AND hist.evt_typ_cd = #{evtTypCd}


               		AND emd.emd_cd = #{emdCd}


					AND evt_outb_dtm  >=  #{startDat}



					AND evt_outb_dtm  <=  #{endDat}



			GROUP BY evt_typ_cd

SELECT log.year AS year, count(log.year) AS count FROM ( SELECT substring(log.evt_outb_dtm, 1, 4) AS year FROM xeus.v_mon_evet_list log WHERE log.evt_typ_cd IS NOT NULL AND test_yn = 'N'
AND log.evt_nm = #{orgNm}
) log GROUP BY log.year ORDER BY log.year

SELECT log.month AS month, count(log.month) AS count FROM ( SELECT substring(log.evt_outb_dtm, 5, 2) AS month FROM xeus.v_mon_evet_list log WHERE log.evt_typ_cd IS NOT NULL AND test_yn = 'N'
AND log.evt_outb_dtm LIKE #{year}||'%'
AND log.evt_nm = #{orgNm}
) log GROUP BY log.month ORDER BY log.month

SELECT log.day AS day, count(log.day) AS count FROM ( SELECT substring(log.evt_outb_dtm, 7, 2) AS day FROM xeus.v_mon_evet_list log WHERE log.evt_typ_cd IS NOT NULL AND test_yn = 'N'
AND log.evt_outb_dtm LIKE #{year}||'%'
AND log.evt_outb_dtm LIKE '____'||#{month}||'%'
AND log.evt_nm = #{orgNm}
) log GROUP BY log.day ORDER BY log.day

SELECT count(log.day) AS count FROM ( SELECT substring(log.evt_outb_dtm, 7, 2) AS day FROM xeus.v_mon_evet_list log WHERE log.evt_typ_cd IS NOT NULL AND test_yn = 'N'
AND log.evt_nm = #{orgNm}
AND log.evt_outb_dtm LIKE #{date}||'%'
) log GROUP BY log.day ORDER BY log.day
